                    <span style="font-size: 10px;">UZS</span>
                    <p class="m-0 font-weight-bold rasxod-stat-sub rasxod-stat-sub-red">	{{rasxod.toString().replace(/(\d)(?=(\d{3})+(\.(\d){0,2})*$)/g, '$1 ')}} <small>сум</small></p>
                  </div>
                  <div style="width: 50%"  class="text-center">
