                    <p class="m-0 font-weight-bold rasxod-stat-sub rasxod-stat-sub-red">	{{dollor_rasxod.toString().replace(/(\d)(?=(\d{3})+(\.(\d){0,2})*$)/g, '$1 ')}} <small>$</small></p>
                  </div>
