            </div>
            <div class="col-4 m-0 pl-1">
              <div class="rasxod-stat-card">
                <div class="border-bottom">
                  <span class="rasxod-stat-title" v-if="all_summ_diff<0"> Разница 
                    <svg xmlns="http://www.w3.org/2000/svg" class="icon icon-tabler icon-tabler-arrow-narrow-up" width="17" height="17" viewBox="0 0 24 24" stroke-width="3" stroke="#ff2825" fill="none" stroke-linecap="round" stroke-linejoin="round">
                      <path stroke="none" d="M0 0h24v24H0z" fill="none"/>
                      <path d="M12 5l0 14" />
                      <path d="M16 9l-4 -4" />
                      <path d="M8 9l4 -4" />
                    </svg>
                  </span>
                  <span class="rasxod-stat-title" v-else> Разница
                    <svg xmlns="http://www.w3.org/2000/svg" class="icon icon-tabler icon-tabler-arrow-down" width="17" height="17" viewBox="0 0 24 24" stroke-width="3" stroke="#00b341" fill="none" stroke-linecap="round" stroke-linejoin="round">
                      <path stroke="none" d="M0 0h24v24H0z" fill="none"/>
                      <path d="M12 5l0 14" />
                      <path d="M18 13l-6 6" />
                      <path d="M6 13l6 6" />
                    </svg>
                  </span>
                  <p class="mt-0 text-right mb-1 rasxod-stat-value" style="font-size: 20px !important;"
                  :class="{'text_success_sum': all_summ_diff>=0, 'text_danger_sum': all_summ_diff<0}"
                  >	{{all_summ_diff.toString().replace(/(\d)(?=(\d{3})+(\.(\d){0,2})*$)/g, '$1 ')}} <small>сум</small></p>
                </div>
                <div class="d-flex">
                  <div style="width: 50%" class="text-center">
                    <span style="font-size: 10px;">UZS</span>
                    <p class="m-0 font-weight-bold rasxod-stat-sub" :class="{'text_success_sum': rasxod_diff>=0, 'text_danger_sum': rasxod_diff<0}"
                    >	{{rasxod_diff.toString().replace(/(\d)(?=(\d{3})+(\.(\d){0,2})*$)/g, '$1 ')}} <small>сум</small></p>
                  </div>
                  <div style="width: 50%"  class="text-center">
                    <span style="font-size: 10px;">USD</span>
                    <p class="m-0 font-weight-bold rasxod-stat-sub" :class="{'text_success_sum': dollor_diff>=0, 'text_danger_sum': dollor_diff<0}"
                      >	{{dollor_diff.toString().replace(/(\d)(?=(\d{3})+(\.(\d){0,2})*$)/g, '$1 ')}} <small>$</small></p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
        <div class="worker_name_search container-fluid mt-2 mb-0">
          <div class="row">
            <div class="col-4 m-0 pl-1">
              <div style="position:relative">
                <input type="text"  placeholder="Сотрудник" class="input_style form-control" 
                  @input="search_worker_name" v-model="worker_name_str" 
                  style="height: 32px;">
                <!-- <small style="position:absolute; top:-17px; left: 0px; font-size: 11px; color: rgb(62, 62, 139);" class="font-weight-bold px-2 py-0">Сотрудник</small> -->
              </div>
            </div>
            <div class="col-4 m-0 pl-1">
              <div style="position:relative">
                <input type="text"  placeholder="Cумма" class="input_style form-control" 
                  @keyup="funcAll_summ_str($event.target.value)" v-model="all_summ_str" 
                  style="height: 32px;">
                <!-- <small style="position:absolute; top:-17px; left: 0px; font-size: 11px; color: rgb(62, 62, 139);" class="font-weight-bold px-2 py-0">Сотрудник</small> -->
              </div>
            </div>
            <div class="col-4 m-0 pl-1">
              <div style="position:relative">
                <input type="text"  placeholder="Примечание" class="input_style form-control" 
                  @input="search_note" v-model="note_str" 
                  style="height: 32px;">
                <!-- <small style="position:absolute; top:-17px; left: 0px; font-size: 11px; color: rgb(62, 62, 139);" class="font-weight-bold px-2 py-0">Сотрудник</small> -->
              </div>
            </div>
          </div>
        </div>
        <div class="workerRasxodTable p-0 pt-2 px-1">
          <table class="rasxodTable">
            <thead style="background-color: #C4DEE4;">
              <tr class="header">
                <th  width="40" class="text-left">№</th>
                <th >{{$t('worker')}}</th>
                <!-- <th >{{$t('born_date')}}</th> -->
                <th >{{$t('summ')}}</th>
                <th >UZS</th>
                <th >USD</th>
                <th width="90">Курс</th>
                <th >Кассир</th>
                <th >{{$t('date')}}</th>
                <th >{{$t('note')}}</th>

              </tr>
            </thead>
            <tbody>
              <tr v-for="(row,rowIndex) in filteredList" :key="rowIndex" 
                :class="{'text_success': row.status_rasxod == 1, 'text_danger': row.status_rasxod == 0}"
                style="cursor:pointer;"
                @click="showRasxodItem(row)">
                <td> <small style="font-size: 11.5px;">{{rowIndex+1}}</small> </td>
                <td> <small style="font-size: 11.5px;">{{row.worker_name}}</small> </td>
                <!-- <td> <small style="font-size: 11.5px;" v-if="row.passport_number">{{row.passport_number.slice(8,10) + '-' + row.passport_number.slice(5,7) + '-' + row.passport_number.slice(0,4)}}</small> </td>  -->
                <td> <small style="font-size: 11.5px;" :class="{'text-success': row.status_rasxod == 1, 'text-danger': row.status_rasxod == 0}">{{row.all_summ_string}}</small> </td>
                <td v-if="row.status_rasxod == 1"> <small style="font-size: 11.5px;" class="text-success">{{row.image_url}}</small> </td>
                <td v-else> <small style="font-size: 11.5px;" class="text-danger">{{row.reserve}}</small> </td>
                <td> <small style="font-size: 11.5px;" :class="{'text-success': row.status_rasxod == 1, 'text-danger': row.status_rasxod == 0}">{{row.dollor_string}}</small> </td>
                <td> <small style="font-size: 11.5px;" v-if="row.kurs">{{row.kurs.toString().replace(/(\d)(?=(\d{3})+(\.(\d){0,2})*$)/g, '$1 ')}}</small> </td>
                <td> <small style="font-size: 11.5px;">{{row.addiotionala_information}}</small> </td>
                <td> <small style="font-size: 11.5px;" v-if="row.created_date">{{row.created_date.slice(8,10) + '-' + row.created_date.slice(5,7) + '-' + row.created_date.slice(0,4)}}</small> <small class="ml-2">{{row.created_date.slice(11,16)}}</small> </td>
                <td> <small style="font-size: 11.5px;">{{row.note}}</small> </td>
              </tr>
            </tbody>
          </table>
        </div>
      </div>
    </div>

     
   
      <mdb-modal :show="show" @close="show = false" size="sm" class="text-center" danger>
        <mdb-modal-header center :close="false">
          <p class="heading">{{$t('Are_you_sure')}}</p>
        </mdb-modal-header>
        <mdb-modal-body>
          <mdb-icon icon="times" size="4x" class="animated rotateIn"/>
        </mdb-modal-body>
        <mdb-modal-footer center>
          <mdb-btn outline="danger" >{{$t('Yes')}}</mdb-btn>
          <mdb-btn color="danger" @click="show = false">{{$t('No')}}</mdb-btn>
        </mdb-modal-footer>
    </mdb-modal>
    <modal-train  :show="show_rasxod_item" headerbackColor="white"  titlecolor="black" title="Ежедневные инфо" 
        @close="show_rasxod_item = false" width="32%">
          <template v-slot:body>
            <info-rasxod
              @close="show_rasxod_item = false"
              v-if="show_rasxod_item"
              :option="show_rasxod_data"
              :qarz-user="qarz_user"
            >
            </info-rasxod>
          </template>
      </modal-train>
    <Toast ref="message"></Toast>
     <massage_box :hide="modal_status" :detail_info="modal_info"
      :m_text="$t('Failed_to_delete')" @to_hide_modal = "modal_status = false"/>
  </div>

</template>

<script>
  import erpSelectKassa from "../../components/erpSelect.vue";
  import erpSelect from "../../components/erpSelectFioSearch.vue";
  import infoRasxod from "./workerRasxod_info.vue"
  import { mdbBtn, mdbBadge, mdbInput, mdbIcon,  mdbModal, mdbModalHeader,   mdbModalBody,mdbModalFooter   } from 'mdbvue';
  import {mapActions, mapGetters, mapMutations} from 'vuex'
  // import 'vue2-datepicker/index.css';
  export default {
    components: {
      mdbBtn,
      mdbModal, mdbModalHeader, mdbIcon, mdbModalBody, mdbModalFooter,
       mdbInput, mdbBadge,
       erpSelect, infoRasxod,erpSelectKassa
    },
    data(){
      return{
        user_id: 0,
        show_rasxod_item: false,
        show_rasxod_data: {},
        qarz_user: null,
        show: false,
        admin:false,
        snipper: true,
        loading:false,
        isPdfGenerating: false,
        editData: {},
        modal_info : '',
        modal_status: false,
        contragent_name: '',
        contragent_id: 0,
        Start_time: null,
        End_time: null,
        group_name: '',
        group_id: null,
        get_payment_list: [],
        index: null,
        service_id: null,
        worker_name: '',

        rasxod: 0,
        prixod: 0,
        all_summ_rasxod: 0,
        dollor_rasxod: 0,
        all_summ_prixod: 0,
        dollor_prixod: 0,

        all_summ_diff: 0,
        rasxod_diff: 0,
        dollor_diff: 0,

        worker_name_str: '',
        all_summ_str: '',
        note_str: '',

        kassa_id: null,
        kassa_name: '',

        json_fields: {
          'Сотрудник': 'worker_name',
          'Дата	': {
            field: "created_date",
            callback: (value) => {
              if(value)
                return  value.slice(8,10) + '-' + value.slice(5,7) + '-' + value.slice(0,4) + '  ' + value.slice(11,16);
              else return ``;
            },
          },
          
          'Приход':{
            callback: (value) => {
              if(value.status_rasxod>0){
                return value.all_summ_string;
              }
              else {
                return ``;
              }
            },
          },
          'Расходь':{
            callback: (value) => {
              if(value.status_rasxod == 0){
                return value.all_summ_string;
              }
              else {
                return ``;
              }
            },
          },
          'UZS': {
            callback: (value) => {
              if(value.status_rasxod>0){
                return value.image_url;
              }
              else if(value.status_rasxod == 0){
                return value.reserve;
              }
              else if(value.status_rasxod == -1){
                return value.reserve;
              }
              else {
                return ``;
              }
            },
          },
          'USD':'dollor_string',
          'Курс': 'kurs',
          'Кассир': 'addiotionala_information',
          'Примечание': 'note',
        },

      }
    },
    async mounted(){
        let time1 = new Date();
        this.Start_time = time1.toISOString().slice(0,10); 
        this.End_time = time1.toISOString().slice(0,10);
        await this.fetchKassa();
        await this.fetchWorker();
        await this.apply();
    },
   
    computed: {
      ...mapGetters(['get_contragent_list', 'allWorker', 'allKassa']),
      filteredList: function(){
        if(this.kassa_name)
        {
          console.log('hiy')
          return this.get_payment_list.filter((item)=>{
            return this.kassa_id == item.auth_user_updator_id
          })
        }else
        {
          return this.get_payment_list;
        }
      },
    },
    methods: {
      ...mapActions(['fetch_contragent', 'fetchWorker', 'fetchKassa']),
      ...mapMutations(['district_row_delete',]),

      selectOption(option){
        console.log(option)
        this.kassa_name = option.name;
        this.kassa_id = option.id;
      },
      async showRasxodItem(data){
        this.show_rasxod_item = true;
        this.show_rasxod_data = data;
        this.qarz_user = null;

        // Agar Qarz bo'limi bo'lsa va reserve_val_l orqali qarzdorlik useri ulangan bo'lsa
        try{
          if (data && data.note && data.note.includes('Qarz bo')) {
            const id = data.reserve_val_l;
            if (id && id > 0) {
              const res = await fetch(this.$store.state.hostname + '/TegirmonQarzdorlikUser/getById?id=' + id);
              if (res.status === 200 || res.status === 201) {
                this.qarz_user = await res.json();
              }
            }
          }
        } catch (e) {
          console.log('Qarzdorlik userni olishda xatolik:', e);
        }
      },
      ensureHtml2Pdf() {
        return new Promise((resolve, reject) => {
          if (window.html2pdf) {
            resolve(window.html2pdf);
            return;
          }

          const existing = document.getElementById("html2pdf-script");
          if (existing) {
            existing.addEventListener("load", () => resolve(window.html2pdf));
            existing.addEventListener("error", () => reject(new Error("html2pdf load failed")));
            return;
          }

          const script = document.createElement("script");
          script.id = "html2pdf-script";
          script.src = "https://cdn.jsdelivr.net/npm/html2pdf.js@0.10.1/dist/html2pdf.bundle.min.js";
          script.onload = () => resolve(window.html2pdf);
          script.onerror = () => reject(new Error("html2pdf load failed"));
          document.body.appendChild(script);
        });
      },
      printDiv() {
        let divContents = document.getElementById("worker_rasxod_print").innerHTML;

        let styles = "";
        document.querySelectorAll('link[rel="stylesheet"], style').forEach((node) => {
          styles += node.outerHTML;
        });

        let printWindow = window.open("", "", "height=800,width=1000");

        let html =
          '<html>' +
          '<head>' +
          '<title>💼 Расход сотрудников</title>' +
          styles +
          '<style>' +
          '@page { size: A4; margin: 5mm; }' +
          '@media print { ' +
          'body { zoom: 0.7; -webkit-print-color-adjust: exact !important; print-color-adjust: exact !important; color-adjust: exact !important; }' +
          '.no-print { display: none !important; }' +
          '.workerRasxodTable { height: auto !important; overflow: visible !important; }' +
          '}' +
          '</style>' +
          '</head>' +
          '<body>' +
          divContents +
          '<script>window.onafterprint = function() { window.close(); }<\/script>' +
          '</body>' +
          '</html>';
        printWindow.document.open();
        printWindow.document.write(html);
        printWindow.document.close();
        printWindow.focus();
        setTimeout(() => {
          printWindow.print();
        }, 1000);
      },
      async savePdf() {
        const tableSource = document.querySelector("#worker_rasxod_print .rasxodTable");
        const headerSource = document.querySelector("#worker_rasxod_print .header_info_rasxod");
        if (!tableSource) return;

        const tempContainer = document.createElement("div");
        tempContainer.style.position = "fixed";
        tempContainer.style.left = "-10000px";
        tempContainer.style.top = "0";
        tempContainer.style.background = "#fff";
        const a4WidthPx = 1100; // A4 landscape at 96dpi
        tempContainer.style.width = `${a4WidthPx}px`;

        const wrapper = document.createElement("div");
        wrapper.style.width = `${a4WidthPx}px`;
        wrapper.style.paddingBottom = "20px";

        const dateRange = document.createElement("div");
        dateRange.style.fontSize = "12px";
        dateRange.style.color = "#3a4b52";
        dateRange.style.margin = "0px 0 0px";
        dateRange.textContent = `${this.Start_time} ➡️ ${this.End_time}`;
        wrapper.appendChild(dateRange);

        if (headerSource) {
          const headerClone = headerSource.cloneNode(true);
          wrapper.appendChild(headerClone);
        }

        const tableClone = tableSource.cloneNode(true);
        tableClone.style.width = `${a4WidthPx}px`;
        wrapper.appendChild(tableClone);

        const pageStyle = document.createElement("style");
        pageStyle.textContent = `
          .header_info_rasxod { page-break-after: avoid; }
          .rasxodTable { page-break-before: auto; }
          .rasxodTable { page-break-inside: auto; }
          .rasxodTable tr { page-break-inside: avoid; page-break-after: auto; break-inside: avoid; }
          .rasxodTable td, .rasxodTable th { page-break-inside: avoid; break-inside: avoid; }
        `;
        wrapper.appendChild(pageStyle);

        tempContainer.appendChild(wrapper);
        document.body.appendChild(tempContainer);

        try {
          this.isPdfGenerating = true;
          await this.$nextTick();
          await new Promise(resolve => setTimeout(resolve, 300));
          const now = new Date();
          const pad = (value) => String(value).padStart(2, "0");
          const timestamp = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())} ${pad(now.getHours())}-${pad(now.getMinutes())}-${pad(now.getSeconds())}`;
          const html2pdf = await this.ensureHtml2Pdf();
          await html2pdf()
            .from(wrapper)
            .set({
              margin: 2,
              filename: `💼 Расход сотрудников (${timestamp}).pdf`,
              pagebreak: { mode: ['css', 'legacy'], avoid: '.rasxodTable tr' },
              html2canvas: { scale: 2.5, useCORS: true, backgroundColor: "#ffffff" },
              jsPDF: { unit: "mm", format: "a4", orientation: "landscape" }
            })
            .save();
        } finally {
          document.body.removeChild(tempContainer);
          this.isPdfGenerating = false;
        }
